// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UserIdentities) predicate.UserIdentities {
	return predicate.UserIdentities(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UserIdentities) predicate.UserIdentities {
	return predicate.UserIdentities(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UserIdentities) predicate.UserIdentities {
	return predicate.UserIdentities(sql.NotPredicates(p))
}
